import json
import os
import sys
import time
import threading
import argparse
import pika


RABBITMQ_HOST = os.getenv("RABBITMQ_HOST", "localhost")
RABBITMQ_PORT = int(os.getenv("RABBITMQ_PORT", "5672"))
QUEUE_NAME = os.getenv("RABBITMQ_QUEUE", "task_queue")


def create_connection():
    credentials = None
    username = os.getenv("RABBITMQ_USERNAME")
    password = os.getenv("RABBITMQ_PASSWORD")
    if username is not None and password is not None:
        credentials = pika.PlainCredentials(username, password)

    parameters = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        heartbeat=60,
        blocked_connection_timeout=30,
    )
    return pika.BlockingConnection(parameters)


def ensure_queue(channel):
    channel.queue_declare(queue=QUEUE_NAME, durable=True)


def publish_task(message, task_type="default", priority=0, delay=0):
    connection = create_connection()
    try:
        channel = connection.channel()
        ensure_queue(channel)

        payload = {
            "task_type": task_type,
            "message": message,
            "priority": priority,
            "delay": delay,
            "created_at": time.time(),
        }

        properties = pika.BasicProperties(
            delivery_mode=2,
            content_type="application/json",
            timestamp=int(time.time()),
        )

        channel.basic_publish(
            exchange="",
            routing_key=QUEUE_NAME,
            body=json.dumps(payload),
            properties=properties,
        )
        print(f"Sent: {payload}")
    finally:
        connection.close()


def process_task(task):
    task_type = task.get("task_type", "default")
    message = task.get("message", "")
    delay = task.get("delay", 0)

    if delay:
        time.sleep(delay)

    print(f"Processed task_type={task_type} message={message}")


def consume_tasks(prefetch_count=1):
    connection = create_connection()
    channel = connection.channel()
    ensure_queue(channel)
    channel.basic_qos(prefetch_count=prefetch_count)

    def callback(ch, method, properties, body):
        try:
            task = json.loads(body.decode("utf-8"))
            process_task(task)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as exc:
            print(f"Error processing message: {exc}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)
    print(f"Waiting for messages on queue '{QUEUE_NAME}'")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        channel.stop_consuming()
    finally:
        connection.close()


def main():
    parser = argparse.ArgumentParser(description="RabbitMQ task publisher/consumer")
    subparsers = parser.add_subparsers(dest="command", required=True)

    publish_parser = subparsers.add_parser("publish", help="Publish a task message")
    publish_parser.add_argument("message", help="Task message")
    publish_parser.add_argument("--task-type", default="default", help="Task type")
    publish_parser.add_argument("--priority", type=int, default=0, help="Task priority")
    publish_parser.add_argument("--delay", type=int, default=0, help="Processing delay in seconds")

    consume_parser = subparsers.add_parser("consume", help="Consume task messages")
    consume_parser.add_argument("--prefetch", type=int, default=1, help="Prefetch count")

    args = parser.parse_args()

    if args.command == "publish":
        publish_task(
            message=args.message,
            task_type=args.task_type,
            priority=args.priority,
            delay=args.delay,
        )
